#!/bin/bash
set -e

PROJECT_ID="web-mansion2026"
REGION="asia-southeast2"
SERVICE_NAME="web-mansion2026"
REPO_NAME="mansion-repo"
IMAGE="${REGION}-docker.pkg.dev/${PROJECT_ID}/${REPO_NAME}/web"

echo "🚀 Deploy Mansion Realty ke Cloud Run"
echo "   Project : ${PROJECT_ID}"
echo "   Region  : ${REGION}"
echo "   Service : ${SERVICE_NAME}"
echo "=================================="

gcloud config set project ${PROJECT_ID}

# Buat Artifact Registry jika belum ada
gcloud artifacts repositories create ${REPO_NAME} \
  --repository-format=docker \
  --location=${REGION} \
  --description="Mansion Realty" 2>/dev/null || echo "✅ Repo sudah ada"

# Auth docker
gcloud auth configure-docker ${REGION}-docker.pkg.dev --quiet

# Build & push image via Cloud Build
cd ~/web-mansion2026
gcloud builds submit --tag ${IMAGE} .

# Deploy ke Cloud Run
gcloud run deploy ${SERVICE_NAME} \
  --image ${IMAGE} \
  --region ${REGION} \
  --platform managed \
  --allow-unauthenticated \
  --port 8080 \
  --memory 1Gi \
  --cpu 1 \
  --min-instances 1 \
  --max-instances 3 \
  --set-env-vars "NEXT_PUBLIC_GAS_API_URL=https://script.google.com/macros/s/AKfycbxK7R5QM3H_4G97UfwHmwL2LmZrXVYggoY3I6VTCfG8RwIC6wRmacwNnOeptMU_X2O65A/exec,GAS_API_SECRET=mansion2026,NEXTAUTH_SECRET=webmansion2026authsecret,NEXT_PUBLIC_WA_OFFICE=628219880889,NEXT_PUBLIC_COMPANY_NAME=MANSION Realty,NEXT_PUBLIC_COMPANY_TAGLINE=Properti Impian Anda Investasi Terbaik Anda,NEXT_PUBLIC_COMPANY_ADDRESS=Jl. Sentra Niaga Utama Ruko Niaga Utama F-7 Citraland Surabaya,NEXT_PUBLIC_COMPANY_EMAIL=manprop26@gmail.com,NEXT_PUBLIC_COMPANY_PHONE=+628219880889,NEXT_PUBLIC_SITE_URL=https://www.mansionpro.id,NEXT_PUBLIC_SITE_DOMAIN=mansionpro.id,GOOGLE_SHEETS_ID=1iHIGVPl7l7dDEVpqHGvZxFVIL8nqUx3G_skBPzFimzI,NEXT_PUBLIC_GA4_ID=G-F0G6ZM1GHN,GA4_PROPERTY_ID=538234936,GA4_SERVICE_ACCOUNT_,CRM_PUBLIC_URL=https://crm.mansionpro.id,CRM_PUBLIC_API_KEY=mansion-web-search-2026"

echo ""
echo "✅ DEPLOY SELESAI!"
gcloud run services describe ${SERVICE_NAME} --region=${REGION} --format="value(status.url)"
